// n8n HTTP node unpacks the JSON array into individual items, one per UV entry.
// We collect all of them with $input.all() instead of $input.first().

const entries = $input.all().map(i => i.json);

console.log(`UV entries received: ${entries.length}. Sample:`, JSON.stringify(entries[0]));

const maxUV = new Map(); // key: `${globalIdLocal}_${data}`

for (const e of entries) {
  if (!e.globalIdLocal || !e.data) continue;
  const uv = parseFloat(e.iUv);
  if (isNaN(uv)) continue;
  const key = `${e.globalIdLocal}_${e.data}`;
  if (!maxUV.has(key) || uv > maxUV.get(key).uv) {
    maxUV.set(key, {
      ipma_global_id: e.globalIdLocal,
      data: e.data,
      uv: Math.round(uv),
    });
  }
}

const rows = [...maxUV.values()];
console.log(`UV: ${rows.length} station-day pairs produced`);
if (rows.length === 0) throw new Error('No UV data — check iUv field name in uv.json');

const values = rows
  .map(r => `(${r.ipma_global_id}, '${r.data}', ${r.uv})`)
  .join(',\n');

const sql = `
UPDATE meteo_diario AS m
SET uv_index = v.uv_index::integer
FROM (
  VALUES ${values}
) AS v(ipma_global_id, data, uv_index)
WHERE m.ipma_global_id = v.ipma_global_id::integer
  AND m.data = v.data::date
`;

return [{ json: { sql, total: rows.length } }];
